-- в”Ђв”Ђ Snikket в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source, self-hosted XMPP-based private messaging server for small communities, with an optional low-cost managed hosting service.$q$, short_description),
  pricing_model = COALESCE($q$freemium (free self-hosted, paid managed hosting)$q$, pricing_model),
  starting_price = COALESCE($q$Free self-hosted; managed hosting from about $6 per month$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Snikket Review 2026: Free Self-Hosted XMPP Messaging Server$q$, seo_title),
  seo_meta_description = COALESCE($q$Snikket is a free, open-source XMPP messaging server for small communities. See features, self-hosting details, apps, and managed hosting pricing from about $6/month.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Snikket is an open-source, self-hosted private messaging platform built on the XMPP (Extensible Messaging and Presence Protocol) open standard. It was publicly unveiled in 2020 at the FOSDEM conference as a collection of existing open-source XMPP components packaged together into an easy-to-deploy alternative to centralized messengers such as WhatsApp, Telegram, Facebook Messenger, and Signal. The server component is built on Prosody, an established XMPP server, with Snikket-specific modules layered on top, and the Android client is based on the well-known Conversations app. Snikket ships as Docker images with a guided setup process, aiming to make running a private messaging server approachable for non-experts while still being fully self-hostable and auditable. Its 'circles' feature helps small communities organize and discover contacts without relying on a public directory, and because it speaks standard XMPP, Snikket users can federate and communicate with people on other compatible XMPP servers rather than being locked into a single walled garden. Messaging is protected with modern TLS encryption, and the platform supports file sharing and voice or video calls. For people who do not want to run their own server, Snikket offers an official managed hosting service priced at roughly six US dollars or less per month for up to ten active users, with a 14-day trial and no long-term lock-in since hosted data can be exported and migrated to a self-hosted instance at any time. The Android app has been translated into over 30 languages by volunteers, while the web portal supports over 10 languages and the iOS app is currently English-only.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e600f81d-f148-4525-b8ff-0baa4cd86eab';

